html,
body {
  min-height: 100%;
  background: var(--mobile-color-bg);
}

body.mobile-body {
  margin: 0;
  overflow-x: hidden;
  color: var(--mobile-color-text);
  font-family: var(--mobile-font-ui);
  -webkit-font-smoothing: antialiased;
  text-rendering: optimizeLegibility;
}

body.mobile-sheet-open {
  overflow: hidden;
}

a {
  color: inherit;
}

button,
input,
select,
textarea {
  font: inherit;
}

.mobile-link {
  color: var(--mobile-color-accent-deep);
  font-weight: 700;
  text-decoration: none;
}

.mobile-link:hover,
.mobile-link:focus,
.mobile-link:active {
  color: var(--mobile-color-accent);
}

.mobile-list {
  margin: 0;
  padding-left: 1.1rem;
  color: var(--mobile-color-text-muted);
  line-height: 1.55;
}

.mobile-list li + li {
  margin-top: 0.45rem;
}

.mobile-copy,
.mobile-muted,
.mobile-helper {
  color: var(--mobile-color-text-muted);
  line-height: 1.55;
}

.mobile-copy {
  font-size: 1rem;
}

.mobile-helper {
  font-size: 0.88rem;
}

.mobile-form-error,
.mobile-flash-alert,
.mobile-flash-notice {
  border-radius: var(--mobile-radius-xl);
  padding: 0.95rem 1rem;
  font-size: 0.95rem;
  box-shadow: var(--mobile-shadow-md);
}

.mobile-form-error,
.mobile-flash-alert {
  color: var(--mobile-color-danger);
  background: var(--mobile-color-warning-soft);
  border: 1px solid rgba(236, 134, 134, 0.24);
}

.mobile-flash-notice {
  color: var(--mobile-color-accent-deep);
  background: var(--mobile-color-accent-soft);
  border: 1px solid rgba(91, 146, 121, 0.24);
}

.mobile-actions {
  display: grid;
  gap: var(--mobile-space-sm);
}

.mobile-button,
.mobile-button-secondary,
.mobile-button-tertiary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

/* The button-* class rules above set `display: inline-flex` with higher
   specificity than the user-agent `[hidden] { display: none }` rule, which
   means buttons toggled via the `hidden` HTML attribute would otherwise
   stay visible. Restore the expected behaviour. */
.mobile-button[hidden],
.mobile-button-secondary[hidden],
.mobile-button-tertiary[hidden] {
  display: none;
}

.mobile-button,
.mobile-button-secondary,
.mobile-button-tertiary {
  width: 100%;
  min-height: 3.5rem;
  border: 0;
  border-radius: var(--mobile-radius-md);
  padding: 0.95rem 1.2rem;
  font-family: var(--mobile-font-system);
  font-size: var(--mobile-text-md);
  font-weight: var(--mobile-weight-semibold);
  line-height: var(--mobile-lh-tight);
  text-decoration: none;
  transition: opacity var(--mobile-duration-fast) var(--mobile-ease),
              background var(--mobile-duration-fast) var(--mobile-ease);
}

.mobile-button {
  color: #fff;
  background: var(--mobile-color-navy);
}

.mobile-button:hover,
.mobile-button:focus,
.mobile-button:active {
  color: #fff;
  opacity: 0.92;
}

.mobile-button:active { opacity: 0.78; }

.mobile-button:disabled {
  opacity: 0.5;
}

.mobile-button-secondary {
  color: var(--mobile-color-text);
  background: #fff;
  border: 1px solid var(--mobile-color-line);
}

.mobile-button-tertiary {
  color: var(--mobile-color-accent-deep);
  background: transparent;
}

.mobile-button-secondary:hover,
.mobile-button-secondary:focus,
.mobile-button-secondary:active,
.mobile-button-tertiary:hover,
.mobile-button-tertiary:focus,
.mobile-button-tertiary:active {
  color: var(--mobile-color-accent-deep);
  opacity: 0.8;
}

.mobile-radio-group,
.mobile-choice-group {
  display: flex;
  flex-direction: column;
}

.mobile-radio-option {
  position: relative;
  overflow: hidden;
  max-height: 6rem;
  opacity: 1;
  transition:
    max-height 300ms cubic-bezier(0.22, 1, 0.36, 1),
    opacity 220ms var(--mobile-ease),
    margin-top 300ms cubic-bezier(0.22, 1, 0.36, 1);
}

.mobile-radio-option + .mobile-radio-option {
  margin-top: var(--mobile-space-xs);
}

.mobile-radio-group.is-collapsed .mobile-radio-option:not(.is-selected) {
  max-height: 0;
  margin-top: 0;
  opacity: 0;
  pointer-events: none;
}

/* Two-up layout: side-by-side options. Used for compact yes/no questions
   where vertical space matters. Falls back gracefully under is-collapsed:
   non-selected option still collapses to max-height: 0, leaving the
   selected option in place. */
.mobile-radio-group--two-up {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--mobile-space-xs);
}

.mobile-radio-group--two-up .mobile-radio-option + .mobile-radio-option {
  margin-top: 0;
}

.mobile-radio-option input {
  position: absolute;
  opacity: 0;
  pointer-events: none;
}

.mobile-radio-option label {
  display: flex;
  align-items: center;
  gap: var(--mobile-space-md);
  min-height: 3.5rem;
  padding: 0.95rem 1rem;
  border: 1px solid transparent;
  border-radius: var(--mobile-radius-md);
  background: var(--mobile-color-surface);
  color: var(--mobile-color-text-muted);
  font-weight: var(--mobile-weight-regular);
  text-align: left;
  cursor: pointer;
  transition: color var(--mobile-duration-fast) var(--mobile-ease),
              background var(--mobile-duration-fast) var(--mobile-ease),
              border-color var(--mobile-duration-fast) var(--mobile-ease);
}

.mobile-radio-option label::before {
  content: "";
  flex-shrink: 0;
  width: 1.125rem;
  height: 1.125rem;
  border-radius: 50%;
  border: 1.5px solid var(--mobile-color-line);
  background: transparent;
  transition: border-color var(--mobile-duration-fast) var(--mobile-ease),
              background var(--mobile-duration-fast) var(--mobile-ease),
              box-shadow var(--mobile-duration-fast) var(--mobile-ease);
}

.mobile-radio-option input:checked + label {
  border-color: var(--mobile-color-accent);
  background: var(--mobile-color-accent-soft);
  color: var(--mobile-color-text);
}

.mobile-radio-option input:checked + label::before {
  border-color: var(--mobile-color-accent);
  background: var(--mobile-color-accent);
  box-shadow: inset 0 0 0 0.22rem var(--mobile-color-surface);
}

.mobile-radio-group.is-collapsed .mobile-radio-option.is-selected label {
  padding-right: 3.4rem;
}

.mobile-radio-reset {
  position: absolute;
  top: 50%;
  right: 0.65rem;
  transform: translateY(-50%);
  width: 2rem;
  height: 2rem;
  border: 0;
  border-radius: 999px;
  background: var(--mobile-color-accent-soft);
  color: var(--mobile-color-accent-deep);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  cursor: pointer;
}

.mobile-radio-reset[hidden] {
  display: none;
}

